/* KCNA glossary - essential terms with authoritative sources. Auto-generated. */
KCNA.registerGlossary([{"term": "Argo CD", "definition": "A declarative, GitOps continuous delivery tool for Kubernetes that uses Git repositories as the source of truth and automatically syncs the desired application state to target clusters.", "domain": "delivery", "sourceUrl": "https://argo-cd.readthedocs.io/en/stable/"}, {"term": "Autoscaling", "definition": "Automatically adjusting compute resources to match demand, such as adding or removing application replicas (horizontal) or cluster nodes so a system stays performant and cost-efficient.", "domain": "architecture", "sourceUrl": "https://kubernetes.io/docs/concepts/workloads/autoscaling/"}, {"term": "CI/CD", "definition": "Continuous Integration and Continuous Delivery/Deployment: automated practices that frequently build, test, and release code changes, enabling fast, reliable, and repeatable software delivery.", "domain": "delivery", "sourceUrl": "https://www.cncf.io/blog/2022/04/06/getting-started-with-ci-cd-pipeline/"}, {"term": "Cloud Native", "definition": "An approach to building and running scalable applications that fully exploit cloud computing, using technologies like containers, microservices, and immutable infrastructure to create loosely coupled systems that are resilient, manageable, and observable.", "domain": "architecture", "sourceUrl": "https://glossary.cncf.io/cloud-native-tech/"}, {"term": "Cluster Autoscaler", "definition": "A Kubernetes tool that automatically adds nodes to a cluster when pods cannot be scheduled due to insufficient resources, and removes underused nodes to save cost.", "domain": "architecture", "sourceUrl": "https://github.com/kubernetes/autoscaler/tree/master/cluster-autoscaler"}, {"term": "CNCF (Cloud Native Computing Foundation)", "definition": "The vendor-neutral home for many fast-growing open source cloud native projects (such as Kubernetes and Prometheus), part of the Linux Foundation, that fosters and sustains the cloud native ecosystem.", "domain": "architecture", "sourceUrl": "https://www.cncf.io/about/who-we-are/"}, {"term": "CNI (Container Network Interface)", "definition": "A specification and set of plugins for configuring network connectivity of containers, used by Kubernetes to set up Pod networking. CNI plugins (such as Calico or Cilium) assign IP addresses and wire up the Pod network.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/"}, {"term": "ConfigMap", "definition": "An API object used to store non-confidential configuration data in key-value pairs, which Pods can consume as environment variables, command-line arguments, or files. It decouples configuration from container images.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/configuration/configmap/"}, {"term": "Container runtime", "definition": "The software responsible for running containers on a node, such as containerd or CRI-O. Kubernetes supports any runtime that implements the Container Runtime Interface (CRI).", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/setup/production-environment/container-runtimes/"}, {"term": "Control plane", "definition": "The set of components that manage the overall state of a Kubernetes cluster, including the API server, scheduler, controller manager, and etcd. It makes global decisions about scheduling and responds to cluster events.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/overview/components/"}, {"term": "Controller", "definition": "A control loop that watches the shared state of the cluster through the API server and makes changes to move the current state toward the desired state. Examples include the Deployment, ReplicaSet, and Job controllers.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/architecture/controller/"}, {"term": "CRI (Container Runtime Interface)", "definition": "The plugin interface that lets the kubelet use a wide variety of container runtimes without recompiling. It defines the gRPC API the kubelet uses to manage containers and images.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/architecture/cri/"}, {"term": "CSI (Container Storage Interface)", "definition": "A standard interface that exposes arbitrary block and file storage systems to containerized workloads in Kubernetes. It lets storage vendors write a single driver that works across orchestrators.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/storage/volumes/"}, {"term": "DaemonSet", "definition": "A controller that ensures a copy of a Pod runs on all (or selected) nodes in the cluster, commonly used for node-level agents like log collectors or monitoring daemons. As nodes are added, the DaemonSet adds Pods to them automatically.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/workloads/controllers/daemonset/"}, {"term": "Declarative Configuration", "definition": "Specifying the desired end state of a system (the 'what') rather than the step-by-step commands to get there (the 'how'), letting the platform reconcile reality to match the declaration.", "domain": "delivery", "sourceUrl": "https://kubernetes.io/docs/concepts/overview/working-with-objects/object-management/"}, {"term": "Deployment", "definition": "A workload resource that manages a stateless set of replica Pods, handling rolling updates and rollbacks declaratively. You describe the desired state and the Deployment controller changes the actual state to match.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/workloads/controllers/deployment/"}, {"term": "etcd", "definition": "A consistent and highly available key-value store used as Kubernetes' backing store for all cluster data and state. It is a core control plane component, and backing it up is critical.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/overview/components/"}, {"term": "FinOps", "definition": "An operational framework and cultural practice that maximizes the business value of cloud and technology spend through collaboration between engineering, finance, and business teams and data-driven cost accountability.", "domain": "delivery", "sourceUrl": "https://www.finops.org/introduction/what-is-finops/"}, {"term": "Flux", "definition": "A set of CNCF-graduated GitOps tools for Kubernetes that keep clusters in sync with configuration stored in Git and automate continuous and progressive delivery.", "domain": "delivery", "sourceUrl": "https://fluxcd.io/"}, {"term": "GitOps", "definition": "An operational model for cloud native systems where the desired state is declared and version-controlled in Git, and software agents automatically pull and continuously reconcile the running system to match it.", "domain": "delivery", "sourceUrl": "https://opengitops.dev/"}, {"term": "Grafana", "definition": "An open source analytics and visualization platform that connects to data sources like Prometheus to build interactive dashboards for monitoring metrics, logs, and traces.", "domain": "architecture", "sourceUrl": "https://grafana.com/oss/grafana/"}, {"term": "Helm Chart", "definition": "A package of pre-configured Kubernetes resource templates, managed by the Helm package manager, that lets you define, install, version, and upgrade applications on Kubernetes.", "domain": "delivery", "sourceUrl": "https://helm.sh/docs/topics/charts/"}, {"term": "HPA (Horizontal Pod Autoscaler)", "definition": "A resource that automatically scales the number of Pod replicas in a workload up or down based on observed metrics such as CPU or memory utilization. It helps applications match capacity to demand without manual intervention.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/tasks/run-application/horizontal-pod-autoscale/"}, {"term": "Immutable Infrastructure", "definition": "An approach where servers and components are never modified after deployment; instead, changes are made by replacing them entirely with new versions, improving consistency and reliability.", "domain": "architecture", "sourceUrl": "https://glossary.cncf.io/immutable-infrastructure/"}, {"term": "Ingress", "definition": "An API object that manages external HTTP and HTTPS access to Services in a cluster, providing routing rules, load balancing, and TLS termination. It requires an Ingress controller to fulfill the rules.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/services-networking/ingress/"}, {"term": "Knative", "definition": "A Kubernetes-based platform for deploying and managing serverless and event-driven workloads, providing request-driven autoscaling (including scale-to-zero) and standardized eventing.", "domain": "architecture", "sourceUrl": "https://knative.dev/docs/"}, {"term": "kube-proxy", "definition": "A network proxy that runs on each node and maintains the network rules that allow communication to Pods through Kubernetes Services. It enables the Service abstraction by routing traffic to the correct backend Pods.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/overview/components/"}, {"term": "kube-scheduler", "definition": "The control plane component that watches for newly created Pods with no assigned node and selects the best node for them to run on. It factors in resource requirements, constraints, affinity, and taints when deciding placement.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/overview/components/"}, {"term": "kubelet", "definition": "The primary node agent that runs on every node and ensures the containers described in PodSpecs are running and healthy. It communicates with the control plane and the container runtime to manage the Pod lifecycle.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/overview/components/"}, {"term": "Kustomize", "definition": "A template-free, declarative tool (built into kubectl as 'apply -k') for customizing raw Kubernetes YAML configurations across environments using overlays and patches.", "domain": "delivery", "sourceUrl": "https://kustomize.io/"}, {"term": "Label and Selector", "definition": "Labels are key-value pairs attached to objects to identify and organize them, while selectors are queries used to filter and group objects by their labels. Together they let controllers and Services target the right set of Pods.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/overview/working-with-objects/labels/"}, {"term": "Logs", "definition": "Timestamped, text-based records of discrete events emitted by applications and infrastructure, used for debugging, auditing, and understanding what happened in a system.", "domain": "architecture", "sourceUrl": "https://opentelemetry.io/docs/concepts/signals/logs/"}, {"term": "Metrics", "definition": "Numeric measurements collected over time (such as CPU usage, request rate, or error count) that are aggregated into time series and used to monitor the health and performance of a system.", "domain": "architecture", "sourceUrl": "https://opentelemetry.io/docs/concepts/signals/metrics/"}, {"term": "Microservices", "definition": "An architectural approach that breaks an application into small, independent services, each focused on a single piece of functionality, that can be developed, deployed, and scaled independently.", "domain": "architecture", "sourceUrl": "https://glossary.cncf.io/microservices-architecture/"}, {"term": "Namespace", "definition": "A mechanism for isolating groups of resources within a single cluster, providing a scope for names and a way to divide cluster resources between multiple users or teams. Resource names must be unique within a namespace but not across namespaces.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/overview/working-with-objects/namespaces/"}, {"term": "NetworkPolicy", "definition": "A specification of how groups of Pods are allowed to communicate with each other and other network endpoints at the IP and port level (OSI layer 3/4). It requires a network plugin that supports NetworkPolicy to take effect.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/services-networking/network-policies/"}, {"term": "Observability", "definition": "A property of a system that measures how well its internal state can be understood from its external outputs (metrics, logs, and traces), enabling operators to ask new questions and take corrective action.", "domain": "architecture", "sourceUrl": "https://glossary.cncf.io/observability/"}, {"term": "OCI (Open Container Initiative)", "definition": "An open governance project that defines industry standards for container image format and runtime, ensuring containers are portable across tools and platforms. Kubernetes container runtimes and images are built around OCI specifications.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/containers/images/"}, {"term": "Open Standards", "definition": "Publicly available, vendor-neutral specifications (such as the Open Container Initiative or CloudEvents) that promote interoperability and portability across cloud native tools and platforms, helping avoid vendor lock-in.", "domain": "architecture", "sourceUrl": "https://opencontainers.org/"}, {"term": "OpenTelemetry (OTel)", "definition": "A vendor-neutral CNCF observability framework and toolkit for generating, collecting, and exporting telemetry data (traces, metrics, and logs) through standardized APIs, SDKs, and the OpenTelemetry Collector.", "domain": "architecture", "sourceUrl": "https://opentelemetry.io/docs/what-is-opentelemetry/"}, {"term": "PersistentVolume (PV)", "definition": "A piece of storage in the cluster that has been provisioned by an administrator or dynamically, existing independently of any Pod's lifecycle. Pods claim it through a PersistentVolumeClaim (PVC) to use durable storage.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/storage/persistent-volumes/"}, {"term": "Pod", "definition": "The smallest deployable unit in Kubernetes, representing one or more containers that share storage, network, and a specification for how to run. Containers in a Pod are always co-located and co-scheduled on the same node.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/workloads/pods/"}, {"term": "Pod Security Standards", "definition": "A set of three cumulative policy levels (Privileged, Baseline, and Restricted) that define security restrictions for Pods, from unrestricted to highly hardened. They are commonly enforced by the built-in Pod Security Admission controller.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/security/pod-security-standards/"}, {"term": "Prometheus", "definition": "An open source, CNCF-graduated monitoring and alerting system that collects metrics as time series via a pull model and queries them with its PromQL language.", "domain": "architecture", "sourceUrl": "https://prometheus.io/docs/introduction/overview/"}, {"term": "RBAC (Role-Based Access Control)", "definition": "A method of regulating access to Kubernetes API resources based on the roles assigned to users, groups, or service accounts. It uses Roles and RoleBindings (namespaced) or ClusterRoles and ClusterRoleBindings (cluster-wide) to grant permissions.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/reference/access-authn-authz/rbac/"}, {"term": "ReplicaSet", "definition": "A controller that maintains a stable set of identical replica Pods running at any given time. It is usually managed by a Deployment rather than created directly.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/workloads/controllers/replicaset/"}, {"term": "Secret", "definition": "An API object for storing small amounts of sensitive data such as passwords, tokens, or keys, keeping them separate from application code and images. By default Secrets are stored base64-encoded and should be protected with additional encryption and RBAC.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/configuration/secret/"}, {"term": "Serverless", "definition": "A computing model that abstracts servers away from the developer, with the cloud provider automatically provisioning, scaling, and managing infrastructure so you pay only for the resources actually used.", "domain": "architecture", "sourceUrl": "https://glossary.cncf.io/serverless/"}, {"term": "Service", "definition": "An abstraction that exposes an application running on a set of Pods as a single, stable network endpoint. It provides a consistent IP and DNS name even as the underlying Pods are created and destroyed.", "domain": "fundamentals", "sourceUrl": "https://kubernetes.io/docs/concepts/services-networking/service/"}, {"term": "Service mesh", "definition": "A dedicated infrastructure layer, typically implemented with sidecar proxies, that handles service-to-service communication including traffic management, security, and observability. Popular examples include Istio and Linkerd, which sit on top of Kubernetes.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/services-networking/service/"}, {"term": "Sidecar container", "definition": "A secondary container that runs in the same Pod as the main application container to provide supporting functionality such as logging, proxying, or monitoring. It shares the Pod's network and storage and runs alongside the primary container.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/workloads/pods/sidecar-containers/"}, {"term": "SLA (Service Level Agreement)", "definition": "An explicit contract with users that includes the SLOs to be met and the consequences (such as financial penalties) for missing them.", "domain": "architecture", "sourceUrl": "https://sre.google/sre-book/service-level-objectives/"}, {"term": "SLI (Service Level Indicator)", "definition": "A carefully defined quantitative measure of some aspect of the level of service provided, such as request latency, error rate, or availability.", "domain": "architecture", "sourceUrl": "https://sre.google/sre-book/service-level-objectives/"}, {"term": "SLO (Service Level Objective)", "definition": "A target value or range for a service level measured by an SLI, for example aiming for 99.9% of requests to succeed over 30 days.", "domain": "architecture", "sourceUrl": "https://sre.google/sre-book/service-level-objectives/"}, {"term": "StatefulSet", "definition": "A workload controller for stateful applications that gives each Pod a stable, unique network identity and persistent storage. It manages ordered deployment, scaling, and updates of its Pods.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/workloads/controllers/statefulset/"}, {"term": "Taint and Toleration", "definition": "Taints are applied to nodes to repel Pods that do not tolerate them, while tolerations are applied to Pods to allow (but not require) scheduling onto matching tainted nodes. Together they control which Pods can be placed on which nodes.", "domain": "orchestration", "sourceUrl": "https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/"}, {"term": "Traces", "definition": "Records that follow a single request as it moves through the multiple services of a distributed system, made up of spans, helping pinpoint latency and failures across service boundaries.", "domain": "architecture", "sourceUrl": "https://opentelemetry.io/docs/concepts/signals/traces/"}, {"term": "VPA (Vertical Pod Autoscaler)", "definition": "A Kubernetes add-on that automatically adjusts the CPU and memory resource requests and limits of pods based on observed usage, right-sizing workloads vertically rather than by replica count.", "domain": "architecture", "sourceUrl": "https://kubernetes.io/docs/concepts/workloads/autoscaling/"}]);
